def _build_codex_exec_command(*, sandbox_mode: str, prompt: str) -> list[str]:
    normalized_sandbox = str(sandbox_mode or "workspace-write").strip() or "workspace-write"
    return [
        "codex",
        "exec",
        "--skip-git-repo-check",
        "--sandbox",
        normalized_sandbox,
        str(prompt or ""),
    ]


