@router.post("/{project_id}/deploy-notify-chat/resolve")
async def resolve_project_deploy_notify_chat(
    project_id: str,
    payload: dict[str, Any] | None = Body(default=None),
    auth_payload: dict = Depends(require_auth),
):
    from services.feishu.feishu_bot_service import resolve_feishu_chat_by_name

    _ensure_permission(auth_payload, "menu.projects")
    _ensure_project_access(project_id, auth_payload)
    body = payload if isinstance(payload, dict) else {}
    platform = _normalize_project_chat_platform(body.get("platform"))
    connector_id = _normalize_project_deploy_text(body.get("connector_id"), limit=120)
    chat_name = _normalize_project_deploy_text(body.get("chat_name") or body.get("name"), limit=200)
    if platform != "feishu":
        raise HTTPException(400, "当前只支持解析飞书群 ID")
    if not connector_id:
        raise HTTPException(400, "请选择通知机器人")
    if not chat_name:
        raise HTTPException(400, "请输入飞书群名称")
    connector = get_bot_connector(connector_id)
    visible_connector = _serialize_project_deploy_notify_connector(dict(connector or {}), project_id)
    if connector is None or visible_connector is None or visible_connector.get("platform") != "feishu":
        raise HTTPException(404, "飞书机器人连接器不存在、未启用或当前项目不可用")
    resolve_identity = _normalize_project_deploy_text(
        body.get("identity") or visible_connector.get("reply_identity") or "bot",
        limit=20,
    ).lower()
    if resolve_identity not in {"bot", "user"}:
        resolve_identity = "bot"
    try:
        chat = resolve_feishu_chat_by_name(dict(connector), chat_name, identity=resolve_identity)
    except Exception as exc:
        raise HTTPException(400, str(exc)) from exc
    chat_id = _normalize_project_deploy_text(chat.get("chat_id"), limit=200)
    if not chat_id:
        raise HTTPException(404, "未解析到飞书群 ID")
    resolved_name = _normalize_project_deploy_text(chat.get("name"), limit=200) or chat_name
    save_bot_connector_scanned_chat(
        connector_id,
        {
            "platform": "feishu",
            "connector_id": connector_id,
            "chat_id": chat_id,
            "chat_name": resolved_name,
            "chat_type": _normalize_project_deploy_text(chat.get("chat_type"), limit=80) or "group",
            "chat_mode": _normalize_project_deploy_text(chat.get("chat_mode"), limit=80),
            "description": _normalize_project_deploy_text(chat.get("description"), limit=300),
            "source": "deploy_notify_resolve",
        },
    )
    return {
        "status": "resolved",
        "project_id": project_id,
        "saved": True,
        "chat": {
            "platform": "feishu",
            "connector_id": connector_id,
            "chat_id": chat_id,
            "chat_name": resolved_name,
            "chat_type": _normalize_project_deploy_text(chat.get("chat_type"), limit=80) or "group",
            "resolve_identity": resolve_identity,
        },
    }


def _read_project_deploy_artifact_content(req: ProjectDeployArtifactPushReq) -> bytes:
    encoded = str(req.artifact_content_base64 or "").strip()
    if encoded:
        try:
            return base64.b64decode(encoded, validate=True)
        except Exception as exc:
            raise HTTPException(400, "artifact_content_base64 is not valid base64") from exc
    artifact_path = _normalize_project_deploy_text(req.artifact_path, limit=2000)
    if not artifact_path:
        raise HTTPException(400, "artifact_content_base64 or server-readable artifact_path is required")
    path = Path(artifact_path).expanduser().resolve()
    if not path.exists() or not path.is_file():
        raise HTTPException(
            400,
            "artifact_path does not exist on the server or is not a file; remote clients must upload artifact_content_base64",
        )
    if path.stat().st_size > 200 * 1024 * 1024:
        raise HTTPException(413, "artifact is larger than 200MB")
    try:
        return path.read_bytes()
    except OSError as exc:
        raise HTTPException(
            400,
            f"failed to read server-side artifact_path: {exc}; remote clients must upload artifact_content_base64",
        ) from exc


async def _read_project_deploy_upload_content(upload: UploadFile) -> bytes:
    content = await upload.read()
    if not content:
        raise HTTPException(400, "artifact file is empty")
    if len(content) > _PROJECT_DEPLOY_ARTIFACT_MAX_BYTES:
        raise HTTPException(413, "artifact is larger than 200MB")
    return content


def _is_project_deploy_upload_file(value: Any) -> bool:
    return bool(getattr(value, "filename", None)) and callable(getattr(value, "read", None))


def _extract_project_deploy_directory_tar_entries(
    *,
    archive_content: bytes,
    manifest: dict[str, Any],
) -> list[dict[str, Any]]:
    if len(archive_content) > _PROJECT_DEPLOY_ARTIFACT_MAX_BYTES:
        raise HTTPException(413, "artifact directory is larger than 200MB")
    try:
        with tarfile.open(fileobj=io.BytesIO(archive_content), mode="r:*") as archive:
            members = [member for member in archive.getmembers() if member.isfile()]
            if len(members) > _PROJECT_DEPLOY_ARTIFACT_MAX_FILES:
                raise HTTPException(
                    413,
                    f"too many artifact files; maximum is {_PROJECT_DEPLOY_ARTIFACT_MAX_FILES}",
                )
            entries: list[dict[str, Any]] = []
            for member in members:
                extracted = archive.extractfile(member)
                if extracted is None:
                    continue
                content = extracted.read()
                entries.append(
                    {
                        "name": Path(member.name).name,
                        "path": member.name,
                        "content": content,
                    }
                )
    except HTTPException:
        raise
    except (tarfile.TarError, OSError, EOFError) as exc:
        raise HTTPException(400, f"invalid artifact directory archive: {exc}") from exc
    if not entries:
        raise HTTPException(400, "artifact directory is empty")
    file_entries_meta = manifest.get("file_entries") if isinstance(manifest.get("file_entries"), list) else []
    if file_entries_meta:
        path_by_index = [
            item.get("path")
            if isinstance(item, dict) and _normalize_project_deploy_text(item.get("path"), limit=1000)
            else ""
            for item in file_entries_meta
        ]
        for index, entry in enumerate(entries):
            if index < len(path_by_index) and path_by_index[index]:
                entry["path"] = path_by_index[index]
    return entries


def _project_deploy_form_text(form: Any, name: str, default: str = "") -> str:
    value = form.get(name, default)
    if _is_project_deploy_upload_file(value):
        return default
    return str(value if value is not None else default)


def _project_deploy_form_int(form: Any, name: str, default: int = 0) -> int:
    value = _project_deploy_form_text(form, name, str(default)).strip()
    try:
        return int(value or default)
    except (TypeError, ValueError):
        return default


def _safe_project_deploy_relative_path(value: Any, *, fallback: str = "") -> str:
    text = str(value or "").replace("\\", "/").strip()
    text = re.sub(r"^[A-Za-z]:", "", text).lstrip("/")
    parts: list[str] = []
    for part in text.split("/"):
        normalized = part.strip()
        if not normalized or normalized in {".", ".."}:
            continue
        parts.append(normalized[:160])
    path = "/".join(parts)
    if path:
        return path[:1000]
    return _safe_project_deploy_relative_path(fallback) if fallback else "artifact-file"


def _build_project_deploy_file_tree(entries: list[dict[str, Any]]) -> list[dict[str, Any]]:
    root_children: dict[str, dict[str, Any]] = {}

    for entry in entries:
        path = _safe_project_deploy_relative_path(entry.get("path"))
        parts = [part for part in path.split("/") if part]
        if not parts:
            continue

        current_children = root_children
        for index, part in enumerate(parts):
            is_file = index == len(parts) - 1
            key = "/".join(parts[: index + 1])
            node = current_children.get(part)
            if node is None:
                node = {
                    "name": part,
                    "path": key,
                    "type": "file" if is_file else "directory",
                    "size": int(entry.get("size") or 0) if is_file else 0,
                    "children": [] if not is_file else [],
                }
                current_children[part] = node
            if is_file:
                node["type"] = "file"
                node["size"] = int(entry.get("size") or 0)
                continue
            node["type"] = "directory"
            node.setdefault("children", [])
            current_children = node.setdefault("_children_map", {})

    nodes = list(root_children.values())
    for node in nodes:
        _strip_project_deploy_tree_maps(node)
    return sorted(nodes, key=lambda item: (item.get("type") == "file", str(item.get("name") or "")))


def _strip_project_deploy_tree_maps(node: dict[str, Any]) -> None:
    children_map = node.pop("_children_map", None)
    if isinstance(children_map, dict):
        node["children"] = list(children_map.values())
    children = node.get("children")
    if isinstance(children, list):
        children.sort(key=lambda item: (item.get("type") == "file", str(item.get("name") or "")))
        for child in children:
            if isinstance(child, dict):
                _strip_project_deploy_tree_maps(child)


def _checksum_project_deploy_file_entries(entries: list[dict[str, Any]]) -> str:
    digest = hashlib.sha256()
    for entry in sorted(entries, key=lambda item: str(item.get("path") or "")):
        digest.update(str(entry.get("path") or "").encode("utf-8"))
        digest.update(b"\0")
        digest.update(entry.get("content") or b"")
        digest.update(b"\0")
    return f"sha256:{digest.hexdigest()}"


def _parse_project_deploy_upload_manifest(
    *,
    manifest_json: str,
    checksum: str,
    size: int,
    version: str,
) -> dict[str, Any]:
    raw_manifest = str(manifest_json or "").strip()
    if len(raw_manifest) > _PROJECT_DEPLOY_ARTIFACT_MANIFEST_MAX_CHARS:
        raise HTTPException(413, "manifest_json is larger than allowed")
    manifest: dict[str, Any] = {}
    if raw_manifest:
        try:
            parsed = json.loads(raw_manifest)
        except json.JSONDecodeError as exc:
            raise HTTPException(400, "manifest_json must be valid JSON") from exc
        if not isinstance(parsed, dict):
            raise HTTPException(400, "manifest_json must be a JSON object")
        manifest.update(parsed)
    checksum_value = _normalize_project_deploy_text(checksum, limit=200)
    if checksum_value:
        manifest["checksum"] = checksum_value
    if size > 0:
        manifest["size"] = size
    version_value = _normalize_project_deploy_text(version, limit=120)
    if version_value:
        manifest["version"] = version_value
    return manifest


def _project_deploy_direct_upload_source_to_temp(
    *,
    upload_files: list[UploadFile],
    manifest: dict[str, Any],
    artifact_name: str,
) -> tuple[TemporaryDirectory[str], Path, str, list[dict[str, Any]], int, str]:
    temp_dir = TemporaryDirectory(prefix="project-deploy-direct-")
    root = Path(temp_dir.name)
    source_type = _normalize_project_deploy_text(manifest.get("source_type"), limit=40).lower()
    file_entries_meta = manifest.get("file_entries") if isinstance(manifest.get("file_entries"), list) else []
    entries: list[dict[str, Any]] = []
    total_size = 0
    digest = hashlib.sha256()
    try:
        if len(upload_files) == 1 and source_type != "directory":
            upload = upload_files[0]
            content = getattr(upload, "_direct_deploy_content", b"")
            if not isinstance(content, bytes) or not content:
                raise HTTPException(400, "deploy source file is empty")
            safe_name = Path(_safe_project_deploy_relative_path(artifact_name or upload.filename)).name or "deploy-file"
            target = root / safe_name
            target.write_bytes(content)
            total_size = len(content)
            digest.update(safe_name.encode("utf-8"))
            digest.update(b"\0")
            digest.update(content)
            entries.append({"path": safe_name, "name": safe_name, "size": len(content)})
            return temp_dir, target, "file", entries, total_size, f"sha256:{digest.hexdigest()}"
        source_root = root / "source"
        source_root.mkdir(parents=True, exist_ok=True)
        for index, upload in enumerate(upload_files):
            content = getattr(upload, "_direct_deploy_content", b"")
            if not isinstance(content, bytes) or not content:
                raise HTTPException(400, "deploy source file is empty")
            meta = file_entries_meta[index] if index < len(file_entries_meta) and isinstance(file_entries_meta[index], dict) else {}
            relative_path = _safe_project_deploy_relative_path(meta.get("path") or upload.filename)
            target = source_root / relative_path
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_bytes(content)
            total_size += len(content)
            digest.update(relative_path.encode("utf-8"))
            digest.update(b"\0")
            digest.update(content)
            digest.update(b"\0")
            entries.append(
                {
                    "path": relative_path,
                    "name": Path(relative_path).name,
                    "size": len(content),
                }
            )
        if not entries:
            raise HTTPException(400, "deploy source is empty")
        return temp_dir, source_root, "directory", entries, total_size, f"sha256:{digest.hexdigest()}"
    except Exception:
        temp_dir.cleanup()
        raise


def _execute_project_desktop_direct_deploy(
    *,
    project: ProjectConfig,
    profile_id: str,
    component_id: str,
    target_ids: list[str],
    artifact_name: str,
    artifact_kind: str,
    manifest: dict[str, Any],
    source_path: Path,
    storage_kind: str,
    file_entries: list[dict[str, Any]],
    total_size: int,
    checksum: str,
    requested_by: str,
    chat_session_id: str,
    task_tree_node_id: str,
    requirement: str,
    plan: str,
    run_deploy_command: bool,
) -> dict[str, Any]:
    profile_id = _normalize_project_deploy_text(profile_id, limit=80) or "prod"
    component_id = _normalize_project_deploy_text(component_id, limit=80)
    profile = _find_project_deploy_profile(project, profile_id)
    if profile is None:
        raise HTTPException(400, f"deploy profile not found: {profile_id}")
    if not bool(profile.get("enabled", True)):
        raise HTTPException(400, f"deploy profile disabled: {profile_id}")
    component = _find_project_deploy_component(profile, component_id)
    if component is None:
        raise HTTPException(400, f"deploy component not found: {component_id or 'default'}")
    if not bool(component.get("enabled", True)):
        raise HTTPException(400, f"deploy component disabled: {component_id or component.get('id') or 'default'}")
    targets = _select_project_deploy_targets(component, target_ids)
    if not targets:
        raise HTTPException(400, "deploy target is required")
    deployable_targets = [target for target in targets if not _project_deploy_target_missing_fields(target, None)]
    if len(deployable_targets) != len(targets):
        missing = _build_project_deploy_missing_target_report(targets=targets, auth_payload=None)
        return {
            "status": "blocked",
            "deployment_confirmed_success": False,
            "stage": "blocked_missing_target_config",
            "project_id": project.id,
            "profile": profile_id,
            "component": _normalize_project_deploy_text(component.get("id") or component_id, limit=80),
            "missing_targets": missing,
            "message": "部署目标缺少 FTP 连接或远端目录，未执行上传",
        }
    artifact = ProjectDeployArtifact(
        id=f"direct-{uuid.uuid4().hex[:12]}",
        project_id=project.id,
        profile=profile_id,
        component=_normalize_project_deploy_text(component.get("id") or component_id, limit=80),
        artifact_name=_normalize_project_deploy_text(artifact_name, limit=240) or source_path.name,
        artifact_kind=_normalize_project_deploy_text(artifact_kind, limit=120)
        or _normalize_project_deploy_text(component.get("artifact_kind"), limit=120)
        or "source-bundle",
        version=_normalize_project_deploy_text(manifest.get("version"), limit=120),
        checksum=checksum,
        size=total_size,
        storage_path=source_path.as_posix(),
        status="direct_deploying",
        manifest={
            **manifest,
            "source": "desktop_agent_direct_deploy",
            "source_type": storage_kind,
            "file_count": len(file_entries),
            "file_entries": file_entries[:1000],
        },
        storage_kind=storage_kind,
        file_tree=_build_project_deploy_file_tree(file_entries),
        uploaded_by=requested_by,
        ready_at=_now_iso(),
    )
    run_id = f"direct-run-{uuid.uuid4().hex[:12]}"
    upload_results: list[dict[str, Any]] = []
    command_results: list[dict[str, Any]] = []
    status = "success"
    stage = "ftp_upload_completed"
    log_excerpt = "desktop direct deploy uploaded original files by FTP"
    for target in deployable_targets:
        try:
            upload_results.append(_project_deploy_direct_upload_to_ftp(artifact=artifact, target=target))
        except Exception as exc:
            status = "failed"
            stage = "upload_failed"
            log_excerpt = f"direct deploy upload failed: {exc}"
            break
    if status == "success":
        command_targets = [
            target
            for target in deployable_targets
            if _project_deploy_target_deploy_command(target)
        ]
        if command_targets and not run_deploy_command:
            status = "blocked"
            stage = "blocked_deploy_command_not_requested"
            log_excerpt = "uploaded original files, but target has deploy_command and direct tool was not allowed to run it"
        else:
            for target in command_targets:
                if not _project_deploy_target_supports_remote_command(target):
                    status = "blocked"
                    stage = "blocked_missing_remote_executor"
                    log_excerpt = "uploaded original files, but target deploy_command has no supported remote executor"
                    break
                try:
                    command_result = _project_deploy_agent_run_configured_remote_command(
                        project=project,
                        target=target,
                        args={},
                        requested_by=requested_by,
                    )
                except Exception as exc:
                    command_result = {
                        "ok": False,
                        "target_id": _normalize_project_deploy_text(target.get("id"), limit=80),
                        "error": str(exc),
                    }
                command_results.append(command_result)
                if not bool(command_result.get("ok")):
                    status = "failed" if not command_result.get("blocked") else "blocked"
                    stage = "deploy_command_failed" if status == "failed" else "blocked_deploy_command"
                    log_excerpt = "configured deploy_command did not complete successfully"
                    break
            if status == "success" and command_targets:
                stage = "deploy_command_completed"
                log_excerpt = "desktop direct deploy uploaded original files and configured deploy_command completed"
    notify_result = _build_project_deploy_notification_preview(
        project,
        artifact,
        status=status,
        run_id=run_id,
        stage=stage,
        log_excerpt=log_excerpt,
        deploy_time=_now_iso(),
        idempotency_scope=f"desktop-direct-{run_id}-{requested_by}",
    )
    return {
        "status": status,
        "deployment_confirmed_success": status == "success",
        "stage": stage,
        "project_id": project.id,
        "profile": profile_id,
        "component": artifact.component,
        "target_ids": [
            _normalize_project_deploy_text(target.get("id"), limit=80)
            for target in deployable_targets
        ],
        "run_id": run_id,
        "artifact": {
            "id": artifact.id,
            "name": artifact.artifact_name,
            "kind": artifact.artifact_kind,
            "storage_kind": storage_kind,
            "size": total_size,
            "checksum": checksum,
            "file_count": len(file_entries),
            "file_tree": artifact.file_tree,
            "persisted_to_deploy_artifacts": False,
        },
        "upload_results": upload_results,
        "command_results": command_results,
        "notify_result": notify_result,
        "requirement": _normalize_project_deploy_text(requirement, limit=2000),
        "plan": _normalize_project_deploy_text(plan, limit=4000),
        "chat_session_id": _normalize_project_deploy_text(chat_session_id, limit=120),
        "task_tree_node_id": _normalize_project_deploy_text(task_tree_node_id, limit=120),
        "log_excerpt": log_excerpt,
    }


def _push_project_deploy_artifact_content(
    *,
    project: ProjectConfig,
    req: ProjectDeployArtifactPushReq,
    uploaded_by: str,
    content: bytes,
) -> dict[str, Any]:
    profile_id = _normalize_project_deploy_text(req.profile, limit=80) or "prod"
    component_id = _normalize_project_deploy_text(req.component, limit=80)
    profile = _find_project_deploy_profile(project, profile_id)
    if profile is None:
        raise HTTPException(400, f"deploy profile not found: {profile_id}")
    if not bool(profile.get("enabled", True)):
        raise HTTPException(400, f"deploy profile disabled: {profile_id}")
    component = _find_project_deploy_component(profile, component_id)
    if component is None:
        raise HTTPException(400, f"deploy component not found: {component_id or 'default'}")
    if not bool(component.get("enabled", True)):
        raise HTTPException(400, f"deploy component disabled: {component.get('id')}")
    manifest = dict(req.manifest or {})
    checksum, size, version = _verify_project_deploy_artifact_manifest(
        artifact_name=_normalize_project_deploy_text(req.artifact_name, limit=240),
        artifact_content=content,
        manifest=manifest,
    )
    manifest["checksum"] = checksum
    manifest["size"] = size
    if version:
        manifest["version"] = version
    archive_suffix = _project_deploy_detect_archive_suffix_from_content(content)
    if archive_suffix:
        manifest["archive_suffix"] = archive_suffix
        manifest["archive_behavior"] = _project_deploy_archive_behavior_label(archive_suffix)
        manifest["server_prepare_behavior"] = "upload_archive_by_default"
    artifact = ProjectDeployArtifact(
        id=project_deploy_store.new_artifact_id(),
        project_id=project.id,
        profile=profile_id,
        artifact_name=_normalize_project_deploy_text(req.artifact_name, limit=240),
        component=_normalize_project_deploy_text(component.get("id"), limit=80),
        artifact_kind=_normalize_project_deploy_text(req.artifact_kind, limit=80)
        or _normalize_project_deploy_text(component.get("artifact_kind"), limit=80)
        or _normalize_project_deploy_text(profile.get("artifact_kind"), limit=80)
        or "source-bundle",
        version=version,
        checksum=checksum,
        size=size,
        status="ready",
        manifest=manifest,
        uploaded_by=uploaded_by,
        ready_at=_now_iso(),
    )
    file_dir = project_deploy_store.artifact_file_dir(project.id, artifact.id)
    file_dir.mkdir(parents=True, exist_ok=True)
    safe_name = Path(artifact.artifact_name).name or f"{artifact.id}.bin"
    storage_path = file_dir / safe_name
    try:
        storage_path.write_bytes(content)
    except OSError as exc:
        raise HTTPException(400, f"failed to store artifact: {exc}") from exc
    artifact.storage_path = str(storage_path)
    project_deploy_store.save_artifact(artifact)
    run = None
    if bool(req.auto_deploy):
        run = _create_project_deploy_run_for_artifact(
            project=project,
            artifact=artifact,
            requested_by=uploaded_by,
            chat_session_id=_normalize_project_deploy_text(req.chat_session_id, limit=120),
            task_tree_node_id=_normalize_project_deploy_text(req.task_tree_node_id, limit=120),
            target_ids=req.target_ids,
        )
        if run is not None:
            deploy_requirement = _normalize_project_deploy_text(req.requirement, limit=2000)
            deploy_plan = _normalize_project_deploy_text(req.plan, limit=4000)
            run.artifact_summary = {
                **(run.artifact_summary or {}),
                "deploy_surface": "project_detail_ai_deploy" if bool(req.ai_deploy) else "deploy_artifact_auto_deploy",
                "deploy_entry": "mcp_or_api_push_auto_deploy",
                **({"user_requirement": deploy_requirement} if deploy_requirement else {}),
                **({"ai_deploy_plan": deploy_plan} if deploy_plan else {}),
                **({"archive_behavior": manifest.get("archive_behavior")} if manifest.get("archive_behavior") else {}),
                **({"archive_suffix": manifest.get("archive_suffix")} if manifest.get("archive_suffix") else {}),
            }
            if run.status == "queued":
                targets = _select_project_deploy_targets(component, req.target_ids)
                run = _execute_project_deploy_run_for_artifact(
                    project=project,
                    artifact=artifact,
                    run=run,
                    targets=targets,
                )
            artifact.deployment_id = run.id
            artifact.status = _project_deploy_artifact_status_for_run(run.status)
            project_deploy_store.save_artifact(artifact)
    return {
        "status": artifact.status,
        "project_id": project.id,
        "profile": profile_id,
        "component": artifact.component,
        "artifact": _serialize_project_deploy_artifact(artifact),
        "deployment": _serialize_project_deploy_run(run) if run else None,
        "checksum_verified": True,
        "auto_deploy": bool(req.auto_deploy),
    }


def _push_project_deploy_artifact_directory_content(
    *,
    project: ProjectConfig,
    req: ProjectDeployArtifactPushReq,
    uploaded_by: str,
    file_entries: list[dict[str, Any]],
) -> dict[str, Any]:
    if not file_entries:
        raise HTTPException(400, "artifact directory is empty")
    total_size = sum(len(entry.get("content") or b"") for entry in file_entries)
    if total_size <= 0:
        raise HTTPException(400, "artifact directory is empty")
    if total_size > _PROJECT_DEPLOY_ARTIFACT_MAX_BYTES:
        raise HTTPException(413, "artifact directory is larger than 200MB")
    profile_id = _normalize_project_deploy_text(req.profile, limit=80) or "prod"
    component_id = _normalize_project_deploy_text(req.component, limit=80)
    profile = _find_project_deploy_profile(project, profile_id)
    if profile is None:
        raise HTTPException(400, f"deploy profile not found: {profile_id}")
    if not bool(profile.get("enabled", True)):
        raise HTTPException(400, f"deploy profile disabled: {profile_id}")
    component = _find_project_deploy_component(profile, component_id)
    if component is None:
        raise HTTPException(400, f"deploy component not found: {component_id or 'default'}")
    if not bool(component.get("enabled", True)):
        raise HTTPException(400, f"deploy component disabled: {component.get('id')}")
    normalized_entries = [
        {
            "path": _safe_project_deploy_relative_path(entry.get("path"), fallback=entry.get("name") or "artifact-file"),
            "name": Path(str(entry.get("path") or entry.get("name") or "artifact-file")).name,
            "size": len(entry.get("content") or b""),
            "content": entry.get("content") or b"",
        }
        for entry in file_entries
    ]
    checksum = _checksum_project_deploy_file_entries(normalized_entries)
    manifest = dict(req.manifest or {})
    manifest["checksum"] = checksum
    manifest["size"] = total_size
    manifest["file_count"] = len(normalized_entries)
    manifest["source_type"] = "directory"
    file_tree_entries = [
        {"path": entry["path"], "name": entry["name"], "size": entry["size"]}
        for entry in normalized_entries
    ]
    file_tree = _build_project_deploy_file_tree(file_tree_entries)
    manifest["file_entries"] = file_tree_entries
    manifest["file_tree"] = file_tree
    version = _normalize_project_deploy_text(manifest.get("version"), limit=120)
    artifact = ProjectDeployArtifact(
        id=project_deploy_store.new_artifact_id(),
        project_id=project.id,
        profile=profile_id,
        artifact_name=_normalize_project_deploy_text(req.artifact_name, limit=240) or "directory-upload",
        component=_normalize_project_deploy_text(component.get("id"), limit=80),
        artifact_kind=_normalize_project_deploy_text(req.artifact_kind, limit=80)
        or _normalize_project_deploy_text(component.get("artifact_kind"), limit=80)
        or _normalize_project_deploy_text(profile.get("artifact_kind"), limit=80)
        or "source-bundle",
        version=version,
        checksum=checksum,
        size=total_size,
        status="ready",
        manifest=manifest,
        storage_kind="directory",
        file_tree=file_tree,
        uploaded_by=uploaded_by,
        ready_at=_now_iso(),
    )
    file_dir = project_deploy_store.artifact_file_dir(project.id, artifact.id)
    content_dir = file_dir / "content"
    try:
        for entry in normalized_entries:
            destination = (content_dir / entry["path"]).resolve()
            if content_dir.resolve() not in destination.parents:
                raise HTTPException(400, "invalid artifact directory path")
            destination.parent.mkdir(parents=True, exist_ok=True)
            destination.write_bytes(entry["content"])
    except OSError as exc:
        raise HTTPException(400, f"failed to store artifact directory: {exc}") from exc
    artifact.storage_path = str(content_dir)
    project_deploy_store.save_artifact(artifact)
    run = None
    if bool(req.auto_deploy):
        run = _create_project_deploy_run_for_artifact(
            project=project,
            artifact=artifact,
            requested_by=uploaded_by,
            chat_session_id=_normalize_project_deploy_text(req.chat_session_id, limit=120),
            task_tree_node_id=_normalize_project_deploy_text(req.task_tree_node_id, limit=120),
            target_ids=req.target_ids,
        )
        if run is not None:
            deploy_requirement = _normalize_project_deploy_text(req.requirement, limit=2000)
            deploy_plan = _normalize_project_deploy_text(req.plan, limit=4000)
            run.artifact_summary = {
                **(run.artifact_summary or {}),
                "deploy_surface": "project_detail_ai_deploy" if bool(req.ai_deploy) else "deploy_artifact_auto_deploy",
                "deploy_entry": "directory_push_auto_deploy",
                **({"user_requirement": deploy_requirement} if deploy_requirement else {}),
                **({"ai_deploy_plan": deploy_plan} if deploy_plan else {}),
            }
            if run.status == "queued":
                targets = _select_project_deploy_targets(component, req.target_ids)
                run = _execute_project_deploy_run_for_artifact(
                    project=project,
                    artifact=artifact,
                    run=run,
                    targets=targets,
                )
            artifact.deployment_id = run.id
            artifact.status = _project_deploy_artifact_status_for_run(run.status)
            project_deploy_store.save_artifact(artifact)
    return {
        "status": artifact.status,
        "project_id": project.id,
        "profile": profile_id,
        "component": artifact.component,
        "artifact": _serialize_project_deploy_artifact(artifact),
        "deployment": _serialize_project_deploy_run(run) if run else None,
        "checksum_verified": True,
        "auto_deploy": bool(req.auto_deploy),
    }


def _push_project_deploy_artifact_payload(
    *,
    project: ProjectConfig,
    req: ProjectDeployArtifactPushReq,
    uploaded_by: str,
) -> dict[str, Any]:
    content = _read_project_deploy_artifact_content(req)
    return _push_project_deploy_artifact_content(
        project=project,
        req=req,
        uploaded_by=uploaded_by,
        content=content,
    )


def _deploy_project_deploy_artifact_payload(
    *,
    project: ProjectConfig,
    artifact_id: str,
    requested_by: str,
    chat_session_id: str = "",
    task_tree_node_id: str = "",
    requirement: str = "",
    plan: str = "",
    execution_plan: dict[str, Any] | None = None,
    target_ids: Any = None,
) -> dict[str, Any]:
    artifact_id_value = _normalize_project_deploy_text(artifact_id, limit=120)
    if not artifact_id_value:
        raise HTTPException(400, "artifact_id is required")
    artifact = project_deploy_store.get_artifact(project.id, artifact_id_value)
    if artifact is None:
        raise HTTPException(404, f"Artifact {artifact_id_value} not found")
    storage_path = Path(artifact.storage_path).expanduser() if artifact.storage_path else None
    if storage_path is None or not storage_path.exists() or not (storage_path.is_file() or storage_path.is_dir()):
        artifact.status = "failed"
        artifact.error = "artifact storage file is missing"
        project_deploy_store.save_artifact(artifact)
        raise HTTPException(400, "服务端 artifact 文件不存在，请重新推送打包产物")
    run = _create_project_deploy_run_for_artifact(
        project=project,
        artifact=artifact,
        requested_by=requested_by,
        chat_session_id=_normalize_project_deploy_text(chat_session_id, limit=120),
        task_tree_node_id=_normalize_project_deploy_text(task_tree_node_id, limit=120),
        require_auto_deploy_enabled=False,
        target_ids=target_ids,
    )
    if run is None:
        artifact.status = "blocked"
        artifact.error = "deploy settings disabled or artifact profile/component not found"
        project_deploy_store.save_artifact(artifact)
        raise HTTPException(400, "项目部署配置未启用，或产物所属环境/部署单元不存在")
    deploy_requirement = _normalize_project_deploy_text(requirement, limit=2000)
    deploy_plan = _normalize_project_deploy_text(plan, limit=4000)
    manifest = artifact.manifest if isinstance(artifact.manifest, dict) else {}
    run.artifact_summary = {
        **(run.artifact_summary or {}),
        "deploy_surface": "project_detail_ai_deploy" if (deploy_requirement or deploy_plan) else "deploy_artifact_manual",
        **({"user_requirement": deploy_requirement} if deploy_requirement else {}),
        **({"ai_deploy_plan": deploy_plan} if deploy_plan else {}),
        **({"ai_execution_plan": execution_plan} if execution_plan else {}),
        **({"archive_behavior": manifest.get("archive_behavior")} if manifest.get("archive_behavior") else {}),
        **({"archive_suffix": manifest.get("archive_suffix")} if manifest.get("archive_suffix") else {}),
    }
    if run.status == "queued":
        profile = _find_project_deploy_profile(project, artifact.profile) or {}
        component = _find_project_deploy_component(profile, artifact.component) or {}
        targets = _select_project_deploy_targets(component, target_ids)
        run = _execute_project_deploy_run_for_artifact(
            project=project,
            artifact=artifact,
            run=run,
            targets=targets,
            execution_plan=execution_plan,
        )
    artifact.deployment_id = run.id
    artifact.status = _project_deploy_artifact_status_for_run(run.status)
    project_deploy_store.save_artifact(artifact)
    return {
        "status": artifact.status,
        "project_id": project.id,
        "artifact": _serialize_project_deploy_artifact(artifact),
        "deployment": _serialize_project_deploy_run(run),
    }


def _fail_project_deploy_artifact_ai_execution_payload(
    *,
    project: ProjectConfig,
    artifact: ProjectDeployArtifact,
    requested_by: str,
    chat_session_id: str,
    requirement: str,
    plan: str,
    stage: str,
    message: str,
    raw_plan: Any = None,
    target_ids: Any = None,
) -> dict[str, Any]:
    run = _create_project_deploy_run_for_artifact(
        project=project,
        artifact=artifact,
        requested_by=requested_by,
        chat_session_id=_normalize_project_deploy_text(chat_session_id, limit=120),
        task_tree_node_id="",
        require_auto_deploy_enabled=False,
        target_ids=target_ids,
    )
    if run is None:
        artifact.status = "failed"
        artifact.error = message
        project_deploy_store.save_artifact(artifact)
        raise HTTPException(400, message)
    run.status = "failed"
    run.stage = _normalize_project_deploy_text(stage, limit=120) or "ai_execution_plan_generation_failed"
    run.log_excerpt = f"AI deployment plan failed: {message}"
    run.artifact_summary = {
        **(run.artifact_summary or {}),
        "deploy_surface": "project_detail_ai_deploy",
        "user_requirement": _normalize_project_deploy_text(requirement, limit=2000),
        "ai_deploy_plan": _normalize_project_deploy_text(plan, limit=4000),
        "uploaded_target_count": 0,
        "ai_execution_plan_error": message,
        **({"ai_execution_plan_raw": raw_plan} if raw_plan else {}),
    }
    artifact.status = "failed"
    artifact.error = run.log_excerpt
    run.notify_result = _build_project_deploy_notification_preview(
        project,
        artifact,
        status=run.status,
        run_id=run.id,
        stage=run.stage,
        log_excerpt=run.log_excerpt,
        deploy_time=run.created_at,
    )
    project_deploy_store.save_artifact(artifact)
    run = project_deploy_store.save_run(run)
    artifact.deployment_id = run.id
    project_deploy_store.save_artifact(artifact)
    return {
        "status": artifact.status,
        "project_id": project.id,
        "artifact": _serialize_project_deploy_artifact(artifact),
        "deployment": _serialize_project_deploy_run(run),
    }


def _send_project_deploy_run_notification_payload(
    *,
    project: ProjectConfig,
    run_id: str,
    requested_by: str,
) -> dict[str, Any]:
    run_id_value = _normalize_project_deploy_text(run_id, limit=120)
    if not run_id_value:
        raise HTTPException(400, "run_id is required")
    run = project_deploy_store.get_run(project.id, run_id_value)
    if run is None:
        raise HTTPException(404, f"Deploy run {run_id_value} not found")
    artifact = project_deploy_store.get_artifact(project.id, run.artifact_id) if run.artifact_id else None
    if artifact is None:
        summary = run.artifact_summary if isinstance(run.artifact_summary, dict) else {}
        artifact = ProjectDeployArtifact(
            id=_normalize_project_deploy_text(run.artifact_id, limit=120) or f"run-{run.id}",
            project_id=project.id,
            profile=run.profile,
            component=run.component,
            artifact_name=_normalize_project_deploy_text(summary.get("artifact_name"), limit=240) or run.artifact_id or run.id,
            artifact_kind=_normalize_project_deploy_text(summary.get("artifact_kind"), limit=120),
            version=_normalize_project_deploy_text(summary.get("version"), limit=120),
            checksum=_normalize_project_deploy_text(summary.get("checksum"), limit=200),
            size=int(summary.get("size") or 0) if str(summary.get("size") or "0").isdigit() else 0,
        )
    notify_result = _build_project_deploy_notification_preview(
        project,
        artifact,
        status=run.status,
        run_id=run.id,
        stage=run.stage,
        log_excerpt=run.log_excerpt,
        deploy_time=run.created_at,
        force_send=True,
        manual=True,
        idempotency_scope=f"manual-{run.id}-{requested_by}-{uuid.uuid4().hex[:8]}",
    )
    if not notify_result:
        raise HTTPException(400, "当前部署单元未配置通知目标")
    previous_results = run.notify_result if isinstance(run.notify_result, list) else []
    run.notify_result = [*previous_results, *notify_result]
    run.artifact_summary = {
        **(run.artifact_summary if isinstance(run.artifact_summary, dict) else {}),
        "manual_notify_requested_by": requested_by,
        "manual_notify_at": _now_iso(),
        "manual_notify_count": len(notify_result),
    }
    run = project_deploy_store.save_run(run)
    return {
        "status": "sent" if any(item.get("status") == "sent" for item in notify_result) else "completed",
        "project_id": project.id,
        "run": _serialize_project_deploy_run(run),
        "notify_result": notify_result,
    }


@router.post("/{project_id}/deploy-artifacts")
async def push_project_deploy_artifact(
    project_id: str,
    req: ProjectDeployArtifactPushReq,
    auth_payload: dict = Depends(require_auth),
):
    _ensure_permission(auth_payload, "menu.projects")
    project = _ensure_project_manage_access(project_id, auth_payload)
    return await run_in_threadpool(
        _push_project_deploy_artifact_payload,
        project=project,
        req=req,
        uploaded_by=_current_username(auth_payload) or "unknown",
    )


@router.post("/{project_id}/deploy-artifacts/upload")
async def upload_project_deploy_artifact(
    project_id: str,
    request: Request,
    auth_payload: dict = Depends(require_auth),
):
    _ensure_permission(auth_payload, "menu.projects")
    project = _ensure_project_manage_access(project_id, auth_payload)
    try:
        form = await request.form(
            max_files=_PROJECT_DEPLOY_ARTIFACT_MAX_FILES,
            max_fields=_PROJECT_DEPLOY_ARTIFACT_MAX_FILES + 100,
            max_part_size=_PROJECT_DEPLOY_ARTIFACT_MANIFEST_MAX_CHARS,
        )
    except Exception as exc:
        detail = str(exc)
        if "Too many files" in detail:
            raise HTTPException(
                413,
                f"too many artifact files; maximum is {_PROJECT_DEPLOY_ARTIFACT_MAX_FILES}",
            ) from exc
        raise HTTPException(400, f"invalid artifact upload form: {detail}") from exc
    profile = _project_deploy_form_text(form, "profile", "prod")
    component = _project_deploy_form_text(form, "component", "")
    artifact_name = _project_deploy_form_text(form, "artifact_name", "")
    artifact_kind = _project_deploy_form_text(form, "artifact_kind", "source-bundle")
    manifest_json = _project_deploy_form_text(form, "manifest_json", "")
    checksum = _project_deploy_form_text(form, "checksum", "")
    size = _project_deploy_form_int(form, "size", 0)
    version = _project_deploy_form_text(form, "version", "")
    chat_session_id = _project_deploy_form_text(form, "chat_session_id", "")
    task_tree_node_id = _project_deploy_form_text(form, "task_tree_node_id", "")
    target_ids_json = _project_deploy_form_text(form, "target_ids_json", "")
    auto_deploy = _project_deploy_form_text(form, "auto_deploy", "false").strip().lower() in {
        "1",
        "true",
        "yes",
        "on",
    }
    ai_deploy = _project_deploy_form_text(form, "ai_deploy", "true").strip().lower() not in {
        "0",
        "false",
        "no",
        "off",
    }
    requirement = _project_deploy_form_text(form, "requirement", "")
    plan = _project_deploy_form_text(form, "plan", "")
    manifest = _parse_project_deploy_upload_manifest(
        manifest_json=manifest_json,
        checksum=checksum,
        size=size,
        version=version,
    )
    target_ids = _normalize_project_deploy_target_ids(target_ids_json) or _normalize_project_deploy_target_ids(manifest.get("target_ids"))
    if target_ids:
        manifest["target_ids"] = target_ids
    upload_files = [item for item in form.getlist("files") if _is_project_deploy_upload_file(item)]
    single_file = form.get("file")
    if _is_project_deploy_upload_file(single_file):
        upload_files = [single_file, *upload_files] if not upload_files else upload_files
    if not upload_files:
        raise HTTPException(400, "artifact file is required")
    source_type = str(manifest.get("source_type") or "").strip().lower()
    req = ProjectDeployArtifactPushReq(
        profile=profile,
        component=component,
        artifact_name=_normalize_project_deploy_text(artifact_name, limit=240)
        or _normalize_project_deploy_text(upload_files[0].filename, limit=240),
        artifact_kind=artifact_kind,
        manifest=manifest,
        auto_deploy=auto_deploy,
        ai_deploy=ai_deploy,
        chat_session_id=chat_session_id,
        task_tree_node_id=task_tree_node_id,
        target_ids=target_ids,
        requirement=requirement,
        plan=plan,
    )
    file_entries_meta = manifest.get("file_entries") if isinstance(manifest.get("file_entries"), list) else []
    if source_type == "directory-tar":
        entries = await run_in_threadpool(
            _extract_project_deploy_directory_tar_entries,
            archive_content=await _read_project_deploy_upload_content(upload_files[0]),
            manifest=manifest,
        )
        return await run_in_threadpool(
            _push_project_deploy_artifact_directory_content,
            project=project,
            req=req,
            uploaded_by=_current_username(auth_payload) or "unknown",
            file_entries=entries,
        )
    if len(upload_files) > 1 or source_type == "directory":
        entries: list[dict[str, Any]] = []
        for index, upload in enumerate(upload_files):
            content = await _read_project_deploy_upload_content(upload)
            meta = file_entries_meta[index] if index < len(file_entries_meta) and isinstance(file_entries_meta[index], dict) else {}
            entries.append(
                {
                    "name": _normalize_project_deploy_text(upload.filename, limit=240),
                    "path": meta.get("path") or upload.filename,
                    "content": content,
                }
            )
        return await run_in_threadpool(
            _push_project_deploy_artifact_directory_content,
            project=project,
            req=req,
            uploaded_by=_current_username(auth_payload) or "unknown",
            file_entries=entries,
        )
    content = await _read_project_deploy_upload_content(upload_files[0])
    return await run_in_threadpool(
        _push_project_deploy_artifact_content,
        project=project,
        req=req,
        uploaded_by=_current_username(auth_payload) or "unknown",
        content=content,
    )


@router.post("/{project_id}/deploy/direct-upload")
async def direct_upload_project_deploy(
    project_id: str,
    request: Request,
    auth_payload: dict = Depends(require_auth),
):
    _ensure_permission(auth_payload, "menu.projects")
    project = _ensure_project_manage_access(project_id, auth_payload)
    try:
        form = await request.form(
            max_files=_PROJECT_DEPLOY_ARTIFACT_MAX_FILES,
            max_fields=_PROJECT_DEPLOY_ARTIFACT_MAX_FILES + 100,
            max_part_size=_PROJECT_DEPLOY_ARTIFACT_MANIFEST_MAX_CHARS,
        )
    except Exception as exc:
        detail = str(exc)
        if "Too many files" in detail:
            raise HTTPException(
                413,
                f"too many deploy source files; maximum is {_PROJECT_DEPLOY_ARTIFACT_MAX_FILES}",
            ) from exc
        raise HTTPException(400, f"invalid direct deploy upload form: {detail}") from exc
    profile = _project_deploy_form_text(form, "profile", "prod")
    component = _project_deploy_form_text(form, "component", "")
    artifact_name = _project_deploy_form_text(form, "artifact_name", "")
    artifact_kind = _project_deploy_form_text(form, "artifact_kind", "source-bundle")
    manifest = _parse_project_deploy_upload_manifest(
        manifest_json=_project_deploy_form_text(form, "manifest_json", ""),
        checksum=_project_deploy_form_text(form, "checksum", ""),
        size=_project_deploy_form_int(form, "size", 0),
        version=_project_deploy_form_text(form, "version", ""),
    )
    target_ids = _normalize_project_deploy_target_ids(
        _project_deploy_form_text(form, "target_ids_json", "")
    ) or _normalize_project_deploy_target_ids(manifest.get("target_ids"))
    run_deploy_command = _project_deploy_form_text(form, "run_deploy_command", "true").strip().lower() not in {
        "0",
        "false",
        "no",
        "off",
    }
    chat_session_id = _project_deploy_form_text(form, "chat_session_id", "")
    task_tree_node_id = _project_deploy_form_text(form, "task_tree_node_id", "")
    requirement = _project_deploy_form_text(form, "requirement", "")
    plan = _project_deploy_form_text(form, "plan", "")
    upload_files = [item for item in form.getlist("files") if _is_project_deploy_upload_file(item)]
    single_file = form.get("file")
    if _is_project_deploy_upload_file(single_file):
        upload_files = [single_file, *upload_files] if not upload_files else upload_files
    if not upload_files:
        raise HTTPException(400, "deploy source file is required")
    total_size = 0
    for upload in upload_files:
        content = await _read_project_deploy_upload_content(upload)
        setattr(upload, "_direct_deploy_content", content)
        total_size += len(content)
    if total_size > _PROJECT_DEPLOY_ARTIFACT_MAX_BYTES:
        raise HTTPException(413, "deploy source is larger than 200MB")
    temp_dir, source_path, storage_kind, file_entries, actual_size, checksum = _project_deploy_direct_upload_source_to_temp(
        upload_files=upload_files,
        manifest=manifest,
        artifact_name=_normalize_project_deploy_text(artifact_name, limit=240)
        or _normalize_project_deploy_text(upload_files[0].filename, limit=240)
        or "deploy-source",
    )
    try:
        return await run_in_threadpool(
            _execute_project_desktop_direct_deploy,
            project=project,
            profile_id=profile,
            component_id=component,
            target_ids=target_ids,
            artifact_name=_normalize_project_deploy_text(artifact_name, limit=240)
            or _normalize_project_deploy_text(upload_files[0].filename, limit=240)
            or "deploy-source",
            artifact_kind=artifact_kind,
            manifest=manifest,
            source_path=source_path,
            storage_kind=storage_kind,
            file_entries=file_entries,
            total_size=actual_size,
            checksum=checksum,
            requested_by=_current_username(auth_payload) or "unknown",
            chat_session_id=chat_session_id,
            task_tree_node_id=task_tree_node_id,
            requirement=requirement,
            plan=plan,
            run_deploy_command=run_deploy_command,
        )
    finally:
        temp_dir.cleanup()


